1877	\begin{lemma}[Mathlib anchor — flatness is local at maximal ideals of the base]
1878	  \label{lem:mathlib_flat_of_localized_maximal}
1879	  \lean{Module.flat_of_localized_maximal}
1880	  \mathlibok
1881	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Localization}).}
1882	  Let \(R\) be a commutative ring and \(M\) an \(R\)-module. If for every maximal
1883	  ideal \(\mathfrak p \subset R\) the localization
1884	  \(M_{\mathfrak p} = \mathrm{LocalizedModule}\,\mathfrak p^c\, M\) is flat over \(R\),
1885	  then \(M\) is flat over \(R\).
1886	\end{lemma}
1887	
1888	\begin{lemma}[Mathlib anchor — flatness over a base is local on the source]
1889	  \label{lem:mathlib_flat_of_isLocalized_maximal}
1890	  \lean{Module.flat_of_isLocalized_maximal}
1891	  \mathlibok
1892	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Localization}).}
1893	  Let \(S\) be an \(R\)-algebra and \(M\) an \(S\)-module, regarded as an
1894	  \(R\)-module through the scalar tower \(R \to S \to M\). Suppose that for every
1895	  maximal ideal \(\mathfrak q \subset S\) the localized module \(M_{\mathfrak q}\)
1896	  (the localization of \(M\) at the prime \(\mathfrak q\) of \(S\), an
1897	  \(S_{\mathfrak q}\)-module and hence an \(R\)-module) is flat over \(R\). Then
1898	  \(M\) is flat over \(R\). \emph{(Flatness over the base ring \(R\) is detected at
1899	  the maximal ideals of the source ring \(S\).)}
1900	\end{lemma}
1901	
1902	\begin{lemma}[Mathlib anchor — transitivity of flatness]
1903	  \label{lem:mathlib_flat_trans}
1904	  \lean{Module.Flat.trans}
1905	  \mathlibok
1906	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Stability}).}
1907	  Let \(R \to S\) be a ring homomorphism and \(M\) an \(S\)-module, viewed as an
1908	  \(R\)-module through the scalar tower. If \(S\) is flat over \(R\) and \(M\) is
1909	  flat over \(S\), then \(M\) is flat over \(R\).
1910	\end{lemma}
1911	
1912	\begin{lemma}[Mathlib anchor — flatness over a base is local on a spanning family of the source]
1913	  \label{lem:mathlib_flat_of_isLocalized_span}
1914	  \lean{Module.flat_of_isLocalized_span}
1915	  \mathlibok
1916	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Localization}).}
1917	  Let \(R\) be a commutative ring, \(S\) an \(R\)-algebra, and \(M\) an \(S\)-module,
1918	  regarded as an \(R\)-module through the scalar tower \(R \to S \to M\). Let
1919	  \(s \subseteq S\) be a subset whose ideal span is all of \(S\)
1920	  (\(\mathrm{Ideal.span}\,s = \top\)), and for each \(r \in s\) let \(M_r\) be an
1921	  away-localization of \(M\) at \(r\) (an \(S_r\)-module, hence an \(R\)-module via the
1922	  tower). If \(M_r\) is flat over \(R\) for every \(r \in s\), then \(M\) is flat over
1923	  \(R\). \emph{(Flatness over the base ring \(R\) descends from a spanning family of
1924	  principal localizations of the \emph{source} ring \(S\).)}
1925	\end{lemma}
1926	
1927	\begin{lemma}
1928	
1929	\leanok
1930	[Flatness transports up a localization tower of the base]
1931	  \label{lem:gf_stalk_flat_localBase}
1932	  \lean{AlgebraicGeometry.gf_stalk_flat_localBase}
1933	  \uses{lem:mathlib_localization_flat, lem:mathlib_flat_trans}
1934	  Let \(R \to R'\) exhibit \(R'\) as the localization of \(R\) at a submonoid
1935	  \(S \subseteq R\), and let \(N\) be an \(R'\)-module, regarded as an \(R\)-module
1936	  through the scalar tower \(R \to R' \to N\). If \(N\) is flat over \(R'\), then \(N\)
1937	  is flat over \(R\). \emph{(Geometric use: with \(R = \OO_{S,x}\),
1938	  \(R' = \OO_{S,p(y)}\) a localization of \(R\) at a generization, and \(N = \F_y\), this
1939	  upgrades flatness of the stalk \(\F_y\) over the local base \(\OO_{S,p(y)}\) to flatness
1940	  over \(\OO_{S,x}\).)}
1941	\end{lemma}
1942	
1943	\begin{proof}
1944	  \uses{lem:mathlib_localization_flat, lem:mathlib_flat_trans}
1945	  \leanok
1946	  The localization \(R'\) is flat over \(R\) (\cref{lem:mathlib_localization_flat}). Since
1947	  \(N\) is flat over \(R'\) by hypothesis, transitivity of flatness along the scalar tower
1948	  \(R \to R' \to N\) (\cref{lem:mathlib_flat_trans}) yields that \(N\) is flat over \(R\).
1949	\end{proof}
