1951	\begin{lemma}[Mathlib anchor — a localized module of a free module is free]
1952	  \label{lem:mathlib_free_of_isLocalizedModule}
1953	  \lean{Module.free_of_isLocalizedModule}
1954	  \mathlibok
1955	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.LocalProperties.Projective}).}
1956	  Let \(R\) be a commutative ring, \(S \subseteq R\) a submonoid, \(R_S\) the localization
1957	  of \(R\) at \(S\), and \(M\) a free \(R\)-module. Let \(f : M \to M_S\) be an \(R\)-linear
1958	  map exhibiting \(M_S\) as the localization of \(M\) at \(S\) (an \(R_S\)-module through the
1959	  scalar tower \(R \to R_S\)). Then \(M_S\) is free over \(R_S\).
1960	\end{lemma}
