1962	\begin{lemma}\leanok
1963	[G3.1 — free patch implies flat patch]
1964	  \label{lem:gf_patch_free_imp_flat}
1965	  \lean{AlgebraicGeometry.gf_patch_free_imp_flat}
1966	  \uses{lem:mathlib_flat_of_free}
1967	  In the situation of the generic-flatness assembly \cref{thm:generic_flatness}, for every
1968	  \(j\) the localized section module \((M_j)_f\) is flat over \(A_f\).
1969	\end{lemma}
1970	
1971	\begin{proof}
1972	  \uses{lem:mathlib_flat_of_free}
1973	  \leanok
1974	  By hypothesis \((M_j)_f\) is free over \(A_f\), and a free module over a
1975	  commutative ring is flat (\cref{lem:mathlib_flat_of_free}). Hence \((M_j)_f\) is
1976	  flat over \(A_f\).
1977	\end{proof}
1978	
1979	\begin{lemma}\leanok
1980	[G3.3 — flatness over a local base is local on the source affine]
1981	  \label{lem:gf_flat_base_local_on_source}
1982	  \lean{AlgebraicGeometry.gf_flat_base_local_on_source}
1983	  \uses{lem:mathlib_flat_of_isLocalized_maximal}
1984	  Let \(R\) be a commutative ring, \(B\) an \(R\)-algebra, and \(N\) a \(B\)-module,
1985	  regarded as an \(R\)-module through the scalar tower \(R \to B \to N\). Suppose
1986	  that for every maximal ideal \(\mathfrak q \subset B\) the localization
1987	  \(N_{\mathfrak q}\) is flat over \(R\). Then \(N\) is flat over \(R\).
1988	\end{lemma}
1989	
1990	\begin{proof}
1991	  \uses{lem:mathlib_flat_of_isLocalized_maximal}
1992	  \leanok
1993	  This is the source-locality criterion for flatness over a fixed base ring,
1994	  instantiated with the canonical localizations \(N_{\mathfrak q}\) of \(N\) at the
1995	  maximal ideals \(\mathfrak q\) of \(B\): each \(N_{\mathfrak q}\) is a localized
1996	  module of \(N\) at the prime \(\mathfrak q\) of the source ring \(B\), and the
1997	  hypothesis supplies the required flatness of every \(N_{\mathfrak q}\) over \(R\).
1998	  \Cref{lem:mathlib_flat_of_isLocalized_maximal} then yields that \(N\) is flat over
1999	  \(R\). \emph{(Note: unlike \cref{lem:mathlib_flat_of_localized_maximal}, which
2000	  localizes over the same ring it tests flatness over, here \(N\) is localized at the
2001	  primes of the source ring \(B\) while flatness is tested over the distinct base
2002	  ring \(R\).)}
2003	\end{proof}
2004	
2005	\begin{lemma}\leanok
2006	[B1.0 — localization commutes with base tensor]
2007	  \label{lem:gf_localizedModule_baseChange_tensor_comm}
2008	  \lean{AlgebraicGeometry.gf_localizedModule_baseChange_tensor_comm}
2009	  Let \(R \to B\) be a ring map, \(T \subseteq B\) a submonoid, \(N\) a \(B\)-module,
2010	  and \(K\) an \(R\)-module. There is an isomorphism, natural in \(K\),
2011	  \[
2012	    \mathrm{LocalizedModule}\,T\,(N \otimes_R K)
2013	      \;\cong\; (\mathrm{LocalizedModule}\,T\,N) \otimes_R K .
2014	  \]
2015	\end{lemma}
2016	\begin{proof}
2017	
2018	\leanok
2019	  Localization is base change: \(\mathrm{LocalizedModule}\,T\,M \cong T^{-1}B \otimes_B M\)
2020	  naturally in the \(B\)-module \(M\). Applying this to \(M = N \otimes_R K\) and using
2021	  associativity/commutativity of the tensor product over the tower
2022	  \(R \to B \to T^{-1}B\) gives
